#include <print>

void fill_buffer(char* buf, int n) {
    for (int i = 0; i < n; ++i)
        buf[i] = static_cast<char>('A' + i % 26);
}

int main() {
    char buf[[indeterminate]] [8];  // явно отказываемся от EB-диагностики
    fill_buffer(buf, 8);           // буфер заполняется целиком до чтения
    buf[7] = '\0';
    std::print("{}\n", buf);
}

