lessons.motivation:
Один из самых коварных источников undefined behavior в C++ — висячие ссылки (dangling references): ссылки, которые пережили объект, на который указывали. Особенно часто этот баг прятался в функциях, возвращающих `const T&` и по ошибке создающих временный объект прямо в `return`-выражении.

```cpp
// Классический баг: временный std::string умирает до выхода из функции,
// вызывающий получает ссылку на уничтоженный объект
const std::string& get_name() {
    return std::string("Alice");  // UB до C++26 — всего лишь предупреждение!
}
```

До C++26 компиляторы выдавали на такой код лишь **предупреждение** (`-Wreturn-local-addr`), и программа продолжала компилироваться и «работать» с неопределённым поведением. C++26 (предложение **P2748** «Disallow Binding a Returned Glvalue to a Temporary») переводит эту категорию ошибок в **ill-formed** — код теперь не компилируется, и компилятор вместо предупреждения выдаёт жёсткую ошибку.

examples.code:
#include <print>
#include <string>

// БЕЗОПАСНО #1: возврат по значению (NRVO делает это эффективным)
std::string get_name() {
    return std::string("Alice");
}

// БЕЗОПАСНО #2: возврат ссылки на долгоживущий (static) объект
const std::string& get_static() {
    static const std::string name = "Bob";
    return name;  // OK: static живёт всё время работы программы
}

// БЕЗОПАСНО #3: lifetime extension — const-ссылка напрямую привязана к временному
void demo_lifetime_extension() {
    const std::string& r = std::string("hello");  // lifetime продлён
    std::print("extended: {}\n", r);  // r действителен здесь
}

int main() {
    std::string name = get_name();
    std::print("{}\n", name);

    const std::string& sr = get_static();
    std::print("{}\n", sr);

    demo_lifetime_extension();
}

#include <print>
#include <string>
#include <utility>

// Функция, просто пересылающая ссылку — НЕ продлевает lifetime!
const std::string& passthru(const std::string& s) { return s; }

int main() {
    // СЛУЧАЙ 1: прямая привязка — lifetime продлевается (OK)
    {
        const std::string& r = std::string("direct");
        std::print("direct: {}\n", r);
    }

    // СЛУЧАЙ 2: const auto& на structured binding — lifetime продлевается (OK)
    {
        auto pair_fn = [] { return std::pair<std::string, int>{"Carol", 30}; };
        const auto& [nm, age] = pair_fn();  // временная пара lifetime-extended
        std::print("{} is {}\n", nm, age);
    }

    // СЛУЧАЙ 3: ссылка на долгоживущий объект через функцию (OK)
    {
        const std::string name = "Dave";
        const std::string& ref = passthru(name);  // name переживает ref
        std::print("via func: {}\n", ref);
    }

    return 0;
}

#include <type_traits>
#include <string>
#include <print>

int main() {
    // const int& привязывается к временному int (из prvalue)
    std::print("const int& <- int: {}\n",
        std::reference_constructs_from_temporary_v<const int&, int>);

    // const double& от int: implicit int->double создаёт временный double
    std::print("const double& <- int: {}\n",
        std::reference_constructs_from_temporary_v<const double&, int>);

    // const string& от const char*: implicit char*->string создаёт временный string
    std::print("const string& <- const char*: {}\n",
        std::reference_constructs_from_temporary_v<const std::string&, const char*>);

    // int& от int: non-const lvalue-ссылка не может привязаться к prvalue
    std::print("int& <- int: {}\n",
        std::reference_constructs_from_temporary_v<int&, int>);

    return 0;
}

