examples.code:
#include <print>

// До C++26: цикл без наблюдаемых побочных эффектов — UB.
// Компилятор мог считать его завершающимся и переставлять код вокруг него.
// C++26: тривиально-пустой бесконечный цикл явно определён как
// «крутиться вечно» — компилятор не вправе его удалить или хоистить.

volatile bool ready = true; // volatile: чтение — наблюдаемый эффект

int main() {
    // C++26: корректно — компилятор не может удалить этот цикл
    while (!ready) {} // спин до установки ready

    std::print("ready\n");
    std::print("spin loops are defined in C++26\n");
}

#include <print>

// P0963: structured binding declaration как условие в if.
// Сам объект привязки служит условием через contextual bool conversion.

struct Lookup {
    bool found;
    int  value;
    explicit operator bool() const { return found; }
};

Lookup search(int key) {
    if (key > 0) return {true, key * 10};
    return {false, 0};
}

int main() {
    // C++26: объявление и проверка в одной строке.
    // found и value доступны в обеих ветках if, но не за его пределами.
    if (auto [found, value] = search(5)) {
        std::print("found={} value={}\n", found, value);
    }

    if (auto [found, value] = search(-1)) {
        std::print("should not print\n");
    } else {
        std::print("not found, value={}\n", value);
    }
}

